import{_ as t,o as a,c as i,a2 as l}from"./chunks/framework.C58al07P.js";const h=JSON.parse('{"title":"Duplicates","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/duplicates.md","filePath":"en/guide/duplicates.md"}'),s={name:"en/guide/duplicates.md"};function o(r,e,c,d,p,u){return a(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="duplicates" tabindex="-1">Duplicates <a class="header-anchor" href="#duplicates" aria-label="Permalink to &quot;Duplicates&quot;">​</a></h1><p>Nid automatically detects duplicate emails in your archives and lets you delete them to save space.</p><hr><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Duplicate detection compares three criteria:</p><ul><li><strong>Subject</strong> of the email</li><li><strong>Sender</strong></li><li><strong>Date</strong> (truncated to the minute)</li></ul><p>Two emails are considered duplicates if they share exactly these three criteria. This typically happens when you archive the same emails multiple times.</p><hr><h2 id="detect-duplicates" tabindex="-1">Detect Duplicates <a class="header-anchor" href="#detect-duplicates" aria-label="Permalink to &quot;Detect Duplicates&quot;">​</a></h2><ol><li>Open the <strong>Duplicates</strong> page in the sidebar</li><li>Duplicates are automatically detected in your archives</li><li>Each duplicate group shows the number of copies and the reclaimable space</li></ol><blockquote><p>📸 <em>Suggested screenshot: Duplicates page with detected duplicate groups (subject, sender, number of copies)</em></p></blockquote><hr><h2 id="delete-duplicates" tabindex="-1">Delete Duplicates <a class="header-anchor" href="#delete-duplicates" aria-label="Permalink to &quot;Delete Duplicates&quot;">​</a></h2><p>For each duplicate group:</p><ol><li>Nid keeps the most recent email</li><li>Click <strong>Delete N duplicates</strong> to remove the extra copies</li><li>EML files and database entries are deleted</li></ol><blockquote><p>📸 <em>Suggested screenshot: delete button on a duplicate group</em></p></blockquote><div class="info custom-block"><p class="custom-block-title">Permanent deletion</p><p>Duplicate deletion is permanent — EML files are removed from the NAS and database records are erased. Make sure they are indeed duplicates before deleting.</p></div><hr><h2 id="gmail-live-duplicates" tabindex="-1">Gmail (Live) Duplicates <a class="header-anchor" href="#gmail-live-duplicates" aria-label="Permalink to &quot;Gmail (Live) Duplicates&quot;">​</a></h2><p>In addition to archives, Nid can also detect duplicates among emails still in your Gmail mailbox.</p>',20)])])}const m=t(s,[["render",o]]);export{h as __pageData,m as default};
